import React, { FunctionComponent } from 'react';
import logo from './logo.svg';
import styled from 'styled-components';

//& si riferisce al Container, è come se scrivessi Container:hover, Container:active, Container:focus, ecc...
//E' come la dichiarazione di una classe
const Container = styled.div`
  width: 300px;
  height: 400px;
  background: black;

  & > dive {
    width: 50px;
    height: 50px;
    background: red;}
`;

const App: FunctionComponent = () => {
  return (
    <Container>
      <div></div>
    </Container>
  );
}

export default App;
